#include <stdio.h>
#include <pthread.h>

/* == EXEMPLE ===============================================
 * Condvar : notification de fin de calcul
 * Un worker signale quand son résultat est prêt.
 * ========================================================= */
pthread_mutex_t ex_mtx = PTHREAD_MUTEX_INITIALIZER;
pthread_cond_t ex_cond = PTHREAD_COND_INITIALIZER;
int ex_done = 0;
int ex_result = 0;

void *ex_worker(void *arg) {
    (void)arg;
    pthread_mutex_lock(&ex_mtx);
    ex_result = 7 * 6;
    ex_done = 1;
    pthread_cond_signal(&ex_cond);
    pthread_mutex_unlock(&ex_mtx);
    return NULL;
}

void example_condvar(void) {
    pthread_t t;
    pthread_create(&t, NULL, ex_worker, NULL);
    pthread_mutex_lock(&ex_mtx);
    while (!ex_done) {
        pthread_cond_wait(&ex_cond, &ex_mtx);
    }
    printf("Resultat: %d\n", ex_result); /* 42 */
    pthread_mutex_unlock(&ex_mtx);
    pthread_join(t, NULL);
}

